          <span className="status-badge" style={getCategoryStyle(currentStatus?.category)}>
            {currentStatus?.status_name || "—"}
          </span>
          {erasureRequired && (
            <p className="tile-sub">Erasure required before sale/disposal</p>
          )}
        </div>

        <div className="tile grade-tile" style={gradeTileStyle}>
          <div>
            <p className="grade-label" style={{ color: gradeColor }}>Grade</p>
            <p className="grade-sub" style={{ color: gradeColor }}>{gradeSub}</p>
          </div>
          <div className="grade-circle" style={{ border: '3px solid ' + gradeColor }}>
            <span className="grade-text" style={{ opacity: gradeOpacity, color: gradeColor }}>{gradeText}</span>
          </div>
        </div>
      </div>

      <div className="divider"></div>

      <div className="status-row">
        <span className="status-label">Update status</span>
        <select
          className="status-select-inline"
          value={currentStatusId || ""}
          onChange={handleStatusChange}
        >
          {statusTypes.map((s) => {
            const blocked = erasureRequired && GATED_CATEGORIES.includes(s.category);
            return (
              <option key={s.status_id} value={s.status_id} disabled={blocked}>
                {s.status_name}{blocked ? " (requires erasure)" : ""}
              </option>
            );
          })}
        </select>
      </div>
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
